const TRUSTED_SOURCES = ['startse.com','exame.com','neofeed.com.br','finsiders.com.br','techtudo.com.br','tecmundo.com.br'];
const COOP_KEYWORDS = ['cooperativa','cooperativismo','fintech','ia','inteligência artificial','open finance','tecnologia'];
const BLOCKED = ['assessoria','press release'];

const news = $input.all()[0].json.news || [];
const scored = [];

for (const item of news) {
  let score = 0.5;
  const url = (item.link || '').toLowerCase();
  const combined = ((item.title || '') + ' ' + (item.snippet || '')).toLowerCase();

  if (TRUSTED_SOURCES.some(s => url.includes(s))) score += 0.2;
  const kwMatches = COOP_KEYWORDS.filter(kw => combined.includes(kw)).length;
  score += Math.min(kwMatches * 0.05, 0.20);
  if (BLOCKED.some(p => combined.includes(p))) score -= 0.3;

  let vertical = 'geral';
  if (combined.match(/sicredi|sicoob|unicred|crédito|fintech|open finance/)) vertical = 'credito';
  else if (combined.match(/agro|agrotech/)) vertical = 'agro';
  else if (combined.match(/unimed|healthtech/)) vertical = 'saude';

  score = Math.min(Math.max(parseFloat(score.toFixed(2)), 0), 1);
  if (score >= 0.70) {
    scored.push({ json: { title: item.title, link: item.link, snippet: item.snippet, source: item.source, date: item.date, source_score: score, vertical } });
  }
}
scored.sort((a, b) => b.json.source_score - a.json.source_score);
return scored.slice(0, 3);

