const item = $input.item;
const content = item.json.message?.content || '';
const scoutData = item.json;
const BANNED = ['disruptivo','sinergia','pensar fora da caixa','estado da arte'];
const checks = {};
checks.density = { passed: content.length >= 2500, detail: `${content.length} chars (mín: 2500)` };
const found = BANNED.filter(w => content.toLowerCase().includes(w));
checks.banned_words = { passed: found.length === 0, detail: found.length ? `Banidas: ${found.join(', ')}` : 'OK' };
checks.unfair_advantage = { passed: content.toLowerCase().includes('vantagem injusta'), detail: 'OK' };
const allPassed = Object.values(checks).every(c => c.passed);
return { json: {
  content,
  gatekeeper_passed: allPassed,
  output_score: allPassed ? 0.95 : 0.50,
  checks,
  vertical: scoutData.vertical || 'geral',
  source_url: scoutData.link || '',
  source_name: scoutData.source || '',
  source_score: scoutData.source_score || 0
}};

const content = $json.content || '';
const headlineMatch = content.match(/##\s*(.+)/);
const headline = headlineMatch ? headlineMatch[1].trim().replace(/[*_]/g,'') : 'CoopTech Innovation';
const leadMatch = content.match(/\*\*A Inovação:\*\*\s*(.+)/);
const lead = leadMatch ? leadMatch[1].trim() : '';
const tldrMatch = content.match(/\*\*TL;DR:\*\*([\s\S]+)$/);
const tldr = tldrMatch ? tldrMatch[1].trim() : '';
const slug = headline.toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g,'').replace(/[^a-z0-9\s-]/g,'').replace(/\s+/g,'-').slice(0,80);
return { json: {
  slug: `${slug}-${Date.now()}`,
  title: headline, lead, content, tldr,
  caderno: 'protocolo', access_level: 'free',
  vertical: $json.vertical || 'geral',
  status: 'published',
  published_at: new Date().toISOString(),
  created_by: 'crew-cooptech-n8n'
}};
